export const GridDrawingSheet: React.FC<{ data: GridDrawingData }> = ({ data }) => {
    const gridDim = data?.gridDim || 6;
    const cellSize = gridDim > 10 ? 25 : 35;
    const totalSize = gridDim * cellSize;
    const showCoords = data?.showCoordinates;

    const renderGrid = (lines: [number, number][][] | null, label: string, isTarget: boolean) => {
        const offset = showCoords ? 25 : 0;
        return (
            <div className="flex flex-col items-center group/grid">
                <div className={`mb-4 px-5 py-2 rounded-2xl border-2 font-black text-[10px] uppercase tracking-[0.2em] transition-all shadow-sm ${isTarget ? 'bg-zinc-900 text-white border-zinc-900' : 'bg-white text-zinc-500 border-zinc-200 group-hover/grid:border-indigo-400 group-hover/grid:text-indigo-600'}`}>
                    {label}
                </div>
                <div className="relative p-2 bg-white border-[6px] border-zinc-900 shadow-2xl rounded-xl">
                    <svg width={totalSize + offset} height={totalSize + offset} className="overflow-visible">
                        {/* Grid Background */}
                        <defs>
                            <pattern id={`grid-${isTarget}`} width={cellSize} height={cellSize} patternUnits="userSpaceOnUse">
                                <rect width={cellSize} height={cellSize} fill="none" stroke="#f1f5f9" strokeWidth="1" />
                            </pattern>
                        </defs>
                        <rect x={offset} y={offset} width={totalSize} height={totalSize} fill={`url(#grid-${isTarget})`} />

                        {/* Coordinates */}
                        {showCoords && (
                            <g>
                                {Array.from({ length: gridDim + 1 }).map((_, i) => (
                                    <React.Fragment key={i}>
                                        <text x={i * cellSize + offset} y={offset - 12} textAnchor="middle" fontSize="10" fontWeight="black" className="fill-zinc-400 font-mono">{String.fromCharCode(65 + i)}</text>
                                        <text x={offset - 12} y={i * cellSize + offset} dominantBaseline="middle" textAnchor="end" fontSize="10" fontWeight="black" className="fill-zinc-400 font-mono">{i + 1}</text>
                                    </React.Fragment>
                                ))}
                            </g>
                        )}

                        <g transform={`translate(${offset}, ${offset})`}>
                            {/* Guide Dots */}
                            {Array.from({ length: (gridDim + 1) * (gridDim + 1) }).map((_, i) => {
                                const r = Math.floor(i / (gridDim + 1));
                                const c = i % (gridDim + 1);
                                return <circle key={i} cx={c * cellSize} cy={r * cellSize} r={isTarget ? "2.5" : "2"} className={isTarget ? "fill-zinc-800" : "fill-zinc-200"} />
                            })}

                            {/* Lines */}
                            {(lines || []).map((line, index) => (
                                line && line.length >= 2 && (
                                    <line
                                        key={index}
                                        x1={line[0][0] * cellSize} y1={line[0][1] * cellSize}
                                        x2={line[1][0] * cellSize} y2={line[1][1] * cellSize}
                                        className="stroke-zinc-900"
                                        strokeWidth="4"
                                        strokeLinecap="round"
                                        strokeLinejoin="round"
                                    />
                                )
                            ))}
                        </g>
                    </svg>
                </div>
            </div>
        );
    };

    const getTransformLabel = (mode: string) => {
        switch(mode) {
            case 'mirror_v': return 'DİKEY AYNA';
            case 'mirror_h': return 'YATAY AYNA';
            case 'rotate_90': return '90° DÖNÜŞ';
            case 'rotate_180': return '180° TERS';
            default: return 'KOPYA MODU';
        }
    }

    return (
        <div className="flex flex-col h-full bg-white p-2">
            <PedagogicalHeader title={data?.title} instruction={data?.instruction} note={data?.pedagogicalNote} />

            <div className="flex-1 flex flex-col gap-16 py-8">
                {(data?.drawings || []).map((drawing, index) => (
                    <EditableElement key={index} className="flex flex-col md:flex-row gap-20 items-center justify-center p-12 bg-[#fcfcfc] rounded-[4rem] border-2 border-zinc-100 break-inside-avoid relative overflow-hidden group shadow-inner">
                        <div className="absolute top-0 right-0 p-8 opacity-[0.03] pointer-events-none transform rotate-12"><i className="fa-solid fa-compass-drafting text-[12rem]"></i></div>

                        {renderGrid(drawing.lines, "REFERANS DESEN", true)}

                        <div className="flex flex-col items-center justify-center gap-4 text-zinc-300">
                             <div className="w-16 h-16 rounded-3xl border-4 border-zinc-200 flex items-center justify-center text-2xl font-black italic shadow-sm bg-white">
                                 <i className="fa-solid fa-wand-magic-sparkles text-indigo-500 animate-pulse"></i>
                             </div>
                             <div className="bg-indigo-600 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest shadow-md">
                                 {getTransformLabel(data.transformMode)}
                             </div>
                             <i className="fa-solid fa-arrow-right text-3xl text-zinc-200"></i>
                        </div>

                        {renderGrid(null, "ÇİZİM ALANI", false)}
                    </EditableElement>
                ))}
            </div>

            <div className="mt-auto pt-8 flex justify-between items-center px-10 border-t border-zinc-100">
                <div className="flex flex-col">
                    <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">Metodoloji</span>
                    <span className="text-[11px] font-bold text-zinc-800">CRA (Somuttan Soyuta) Model</span>
                </div>
                <p className="text-[8px] text-zinc-300 font-bold uppercase tracking-[0.5em]">Bursa Disleksi AI • Görsel-Uzamsal Laboratuvarı</p>
                <div className="flex gap-1">
                    <div className="w-2 h-2 rounded-full bg-indigo-500"></div>
                    <div className="w-2 h-2 rounded-full bg-indigo-200"></div>
                </div>
            </div>
        </div>
    );
};

