        </div>
        <span className="text-[11px] font-bold text-zinc-600 dark:text-zinc-300 group-hover:text-zinc-900">{label}</span>
        <input type="checkbox" className="hidden" checked={checked} onChange={e => onChange(e.target.checked)} />
    </label>
);

