    [İPUCU DERİNLİĞİ]: Her bilmece için tam ${gridSize} adet kesin önerme/ipucu yaz.
    [SAYFA YAPISI]: Her sayfada ${itemCount} adet bağımsız bento-grid bloğu olmalı.

    ÖZEL KURALLAR:
    1. İpuçları "Sadece X değil" veya "X ile Y arasında" gibi disleksi dostu, somut ve mantıksal olmalı.
    2. Seçenekler birbirine yakın ama tek bir cevap doğru olmalı.
    3. ${showSumTarget ? "[YÖNETİCİ İŞLEV]: 'sumTarget' alanına sayfadaki tüm doğru cevapların toplamını yaz. Bu, öğrencinin dikkatini tüm sayfaya yaymasını sağlar." : ""}

    ÖNEMLİ: Sadece JSON döndür. Multimodal zekanı kullanarak her bilmece için bir "visualHint" (İngilizce SVG promptu) ekle.
    `;

    const prompt = getMathPrompt("Gelişmiş Sayısal Mantık Bilmeceleri", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                sumTarget: { type: Type.INTEGER },
                sumMessage: { type: Type.STRING },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            riddle: { type: Type.STRING },
                            visualHint: { type: Type.STRING },
                            boxes: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.INTEGER } } },
                            options: { type: Type.ARRAY, items: { type: Type.STRING } },
                            answer: { type: Type.STRING },
                            answerValue: { type: Type.INTEGER }
                        },
                        required: ['riddle', 'boxes', 'options', 'answer', 'answerValue']
                    }
                }
            },
            required: ['title', 'puzzles']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

import { GeneratorOptions, NumberPatternData, NumberPyramidData, OddEvenSudokuData, KendokuData, BasicOperationsData, MoneyCountingData, MathMemoryCardsData, ClockReadingData, RealLifeProblemData, MathPuzzleData, NumberLogicRiddleData } from '../../types';
import { shuffle, getRandomInt, getRandomItems, TR_VOCAB } from './helpers';

// NUMBER LOGIC RIDDLES (Offline Enhanced)
export const generateOfflineNumberLogicRiddles = async (options: GeneratorOptions): Promise<NumberLogicRiddleData[]> => {
    const { worksheetCount, numberRange, difficulty, logicModel, itemCount = 4 } = options;

    const [minRange, maxRange] = (numberRange || '1-50').split('-').map(Number);
    const pages: NumberLogicRiddleData[] = [];

    for (let p = 0; p < worksheetCount; p++) {
        const puzzles = [];
        let runningTotal = 0;

        for (let i = 0; i < itemCount; i++) {
            const n = getRandomInt(minRange, maxRange);
            const hints = [];

            // Logic Building
            if (logicModel === 'identity' || !logicModel) {
                if (n % 2 === 0) hints.push("Ben bir çift sayıyım.");
                else hints.push("Ben bir tek sayıyım.");

                if (n > (maxRange / 2)) hints.push(`${Math.floor(maxRange/2)}'den büyüğüm.`);
                else hints.push(`${Math.floor(maxRange/2)}'den küçüğüm.`);

                if (difficulty === 'Zor' || difficulty === 'Uzman') {
                    const sumDigits = n.toString().split('').reduce((acc, curr) => acc + parseInt(curr), 0);
                    hints.push(`Rakamlarım toplamı ${sumDigits}'dir.`);
                }
            } else if (logicModel === 'sequence') {
                const step = getRandomInt(2, 5);
                hints.push(`Kuralı bul: ${n-step*2}, ${n-step}, ... ?`);
            } else {
                hints.push(`${n-1}'den büyük, ${n+1}'den küçük bir sayıyım.`);
                hints.push(`Beni 2 ile çarparsan ${n*2} elde edersin.`);
            }

            // Options Matrix (Simulated visual boxes)
            const boxes = Array.from({ length: 5 }, () => {
                return [getRandomInt(minRange, maxRange), getRandomInt(minRange, maxRange)];
            });
            boxes[getRandomInt(0, 4)][0] = n;

            // Multiple Choice Options
            const distractors = new Set<number>();
            while(distractors.size < 3) {
                const d = getRandomInt(minRange, maxRange);
                if (d !== n) distractors.add(d);
            }
            const allOptions = shuffle([n.toString(), ...Array.from(distractors).map(d => d.toString())]);
            const correctLetter = ['A', 'B', 'C', 'D'][allOptions.indexOf(n.toString())];

            puzzles.push({
                riddle: hints.join(' '),
                visualHint: 'math_icon',
                boxes,
                options: allOptions,
                answer: `${correctLetter} - ${n}`,
                answerValue: n
            });

            runningTotal += n;
        }

        pages.push({
            title: "Sayısal Mantık Bilmeceleri",
            instruction: "Bilmeceleri çöz, doğru şıkkı bul ve tüm cevapların toplamıyla büyük hedefe ulaş!",
            pedagogicalNote: "Çalışma belleği, sayı hissi ve mantıksal çıkarım becerilerini geliştirir. Toplam hedefi özelliği öğrencinin dikkatini tüm sayfada tutmasını sağlar.",
            sumTarget: runningTotal,
            sumMessage: `Bu sayfadaki tüm doğru cevapların toplamı tam olarak ${runningTotal} olmalıdır. Kontrol etmeyi unutma!`,
            puzzles
        });
    }

    return pages;
};

