import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, HiddenPasswordGridData } from '../../types';

const PEDAGOGICAL_PROMPT = `
[ROL: KIDEMLİ EĞİTİM MATERYALİ TASARIMCISI]
Görevin: Disleksik çocuklar için dikkat ve görsel tarama becerilerini geliştiren materyaller üretmek.
Uzman seviyesi için:
1. Birbirine görsel olarak çok benzeyen çeldiriciler kullan (Örn: b, d, p, q veya m, n, u).
2. Tek bir çeldirici yerine 2 veya 3 farklı "hedef harf" belirle.
3. Gizli kelimeler biraz daha uzun (5-8 harf) olabilir.
4. Yönergeler kısa, net ve teşvik edici olmalıdır.
Sadece JSON döndür.
`;

export const generateHiddenPasswordGridFromAI = async (options: GeneratorOptions): Promise<HiddenPasswordGridData[]> => {
    const { topic, difficulty, worksheetCount, gridSize = 5, itemCount = 9, case: letterCase } = options;

    const isExpert = difficulty === 'Zor' || difficulty === 'Uzman';
    const targetCount = isExpert ? 3 : 1;

    const prompt = `
    "Gizli Şifre Matrisi" (Letter Cancellation) etkinliği üret. 
    Konu: ${topic || 'Karışık'}. Zorluk: ${difficulty}.

    PARAMETRELER:
    - Sayfa başı blok sayısı: ${itemCount}
    - Matris boyutu: ${gridSize}x${gridSize}
    - Harf Tipi: ${letterCase === 'upper' ? 'SADECE BÜYÜK HARFLER' : 'SADECE KÜÇÜK HARFLER'}

    KURALLAR:
    1. Her blok için tam ${targetCount} adet 'targetLetters' (çeldirici harfler) seç. 
    2. Uzman modundaysan (Difficulty: ${difficulty}), çeldiricileri birbirine benzeyenlerden seç (örn: b ve d).
    3. Gizli kelimeler 3-8 harf arasında olmalı.
    4. Matrisi 'targetLetters' ile doldur, aralara gizli kelimenin harflerini soldan sağa akacak şekilde serpiştir.

    ${PEDAGOGICAL_PROMPT}
    ${worksheetCount} adet çalışma sayfası üret.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                settings: {
                    type: Type.OBJECT,
                    properties: {
                        gridSize: { type: Type.NUMBER },
                        itemCount: { type: Type.NUMBER },
                        cellStyle: { type: Type.STRING },
                        letterCase: { type: Type.STRING }
                    }
                },
                grids: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            targetLetters: { type: Type.ARRAY, items: { type: Type.STRING } },
                            hiddenWord: { type: Type.STRING },
                            grid: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } }
                        },
                        required: ['targetLetters', 'hiddenWord', 'grid']
                    }
                }
            },
            required: ['title', 'instruction', 'grids']
        }
    };

    const result = await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
    return result.map((page: any) => ({
        ...page,
        settings: {
            gridSize,
            itemCount,
            cellStyle: options.variant || 'square',
            letterCase: letterCase || 'upper'
        }
    }));
};

import { GeneratorOptions, HiddenPasswordGridData } from '../../types';
import { getWordsForDifficulty, getRandomItems, turkishAlphabet, shuffle } from './helpers';

const SIMILAR_GROUPS = [
    ['B', 'D', 'P'], ['M', 'N', 'U'], ['E', 'F', 'L'], 
    ['S', 'Ş', 'Z'], ['I', 'İ', 'L'], ['O', 'Ö', 'C']
];

export const generateOfflineHiddenPasswordGrid = async (options: GeneratorOptions): Promise<HiddenPasswordGridData[]> => {
    const { topic, difficulty, worksheetCount, gridSize = 5, itemCount = 9, case: letterCase } = options;
    const results: HiddenPasswordGridData[] = [];

    const isExpert = difficulty === 'Zor' || difficulty === 'Uzman';
    const targetCount = isExpert ? 3 : 1;

    const wordPool = getWordsForDifficulty(difficulty, topic || 'Rastgele').filter(w => w.length >= 3 && w.length <= gridSize + 2);

    for (let i = 0; i < worksheetCount; i++) {
        const grids = [];
        const selectedWords = getRandomItems(wordPool, itemCount);

        for (const word of selectedWords) {
            let processedWord = letterCase === 'upper' ? word.toLocaleUpperCase('tr') : word.toLocaleLowerCase('tr');

            // Choose target letters based on difficulty
            let targetLetters: string[] = [];
            if (isExpert) {
                const group = SIMILAR_GROUPS[Math.floor(Math.random() * SIMILAR_GROUPS.length)];
                targetLetters = getRandomItems(group, targetCount);
            } else {
                const alphabet = turkishAlphabet.toLocaleUpperCase('tr').split('');
                const potentialTargets = alphabet.filter(l => !processedWord.toUpperCase().includes(l));
                targetLetters = [getRandomItems(potentialTargets, 1)[0]];
            }

            if (letterCase === 'lower') {
                targetLetters = targetLetters.map(l => l.toLocaleLowerCase('tr'));
            }

            const totalCells = gridSize * gridSize;
            const matrix = Array.from({ length: gridSize }, () => 
                Array(gridSize).fill(null).map(() => targetLetters[Math.floor(Math.random() * targetLetters.length)])
            );

            // Random but ordered positions for hidden word
            const availablePositions = Array.from({ length: totalCells }, (_, i) => i);
            const wordPositions = getRandomItems(availablePositions, processedWord.length).sort((a, b) => a - b);

            wordPositions.forEach((pos, idx) => {
                const r = Math.floor(pos / gridSize);
                const c = pos % gridSize;
                matrix[r][c] = processedWord[idx];
            });

            grids.push({ targetLetters, hiddenWord: processedWord, grid: matrix });
        }

        results.push({
            title: 'Gizli Şifre Matrisi (Uzman Seviye)',
            instruction: isExpert 
                ? 'Grup içindeki TÜM hedef harfleri eleyiniz. Kalan harfler gizli şifreyi oluşturur.' 
                : 'Hedef harfi kutularda karalayınız. Kalan harflerden şifreyi bulun.',
            pedagogicalNote: 'Görsel tarama, seçici dikkat ve ketleme (inhibisyon) becerilerini üst düzeyde zorlar.',
            settings: { 
                gridSize, 
                itemCount, 
                cellStyle: options.variant as any || 'square', 
                letterCase: letterCase as any || 'upper' 
            },
            grids
        });
    }
    return results;
};

