import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, FindTheDifferenceData } from '../../types';

const PEDAGOGICAL_PROMPT = `
[ROL: KIDEMLİ ÖZEL EĞİTİM PROFÖSÖRÜ VE GÖRSEL ALGI UZMANI]
Görevin: Disleksik çocuklar için "Görsel Ayrıştırma" becerilerini zorlayan hatasız materyaller üretmek.
Üretilen her satırda, seçilen "Fark Türü"ne uygun olarak disleksi risk grubunun en çok hata yaptığı (visual similarity) öğeleri seç.
Sadece JSON döndür.
`;

export const generateFindTheDifferenceFromAI = async (options: GeneratorOptions): Promise<FindTheDifferenceData[]> => {
    const { difficulty, itemCount = 8, worksheetCount, findDiffType = 'linguistic', distractionLevel = 'medium', gridSize = 4, studentContext } = options;

    const typeDesc = {
        'linguistic': 'Harf Ayrıştırma (Ayna harfler b-d, p-q, m-n, u-ü vb.)',
        'numeric': 'Rakam Ayrıştırma (6-9, 2-5, 3-8, 1-7 benzerliği vb.)',
        'semantic': 'Kelime Ayrıştırma (kale-lale, dere-dede, baba-dada vb.)',
        'pictographic': 'Sembolik Ayrıştırma (Ok yönleri, konum farkları, milimetrik açı farkları)'
    }[findDiffType] || 'Harf Ayrıştırma';

    const prompt = `
    "Farkı Bul" (Visual Discrimination) etkinliği üret.

    KESİN PARAMETRELER:
    - ODAK ALAN: ${typeDesc}.
    - ZORLUK: ${difficulty}.
    - ÇELDİRİCİ ŞİDDETİ (Farkın Belirginliği): ${distractionLevel}.
    - SATIR BAŞI ÖĞE: TAM OLARAK ${gridSize} adet.
    - TOPLAM GÖREV (SATIR): TAM OLARAK ${itemCount} adet.

    KURALLAR:
    1. Her satırda (row) birbirine ÇOK benzeyen öğeler kullan.
    2. Farklı olan öğe (odd-one), diğerlerinden seçilen '${distractionLevel}' seviyesine göre ayrılmalı.
    3. Ekstrem seviyede farklar sadece font kalınlığı, küçük bir rotasyon veya bir nokta kadar az olabilir.

    ${PEDAGOGICAL_PROMPT}
    ${worksheetCount} adet çalışma sayfası üret.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                rows: { 
                    type: Type.ARRAY, 
                    items: { 
                        type: Type.OBJECT, 
                        properties: { 
                            items: { type: Type.ARRAY, items: { type: Type.STRING } }, 
                            correctIndex: { type: Type.INTEGER }, 
                            visualDistractionLevel: { type: Type.STRING } 
                        }, 
                        required: ['items', 'correctIndex'] 
                    } 
                }
            },
            required: ['title', 'instruction', 'rows', 'pedagogicalNote']
        }
    };

    return generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

import { 
    FindTheDifferenceData, GeneratorOptions 
} from '../../types';
import { getRandomInt, getRandomItems, shuffle } from './helpers';

const CRITICAL_PAIRS: Record<string, string[][]> = {
    linguistic: [['b', 'd'], ['p', 'q'], ['m', 'n'], ['u', 'n'], ['a', 'e'], ['s', 'z'], ['t', 'f'], ['ğ', 'g'], ['ı', 'i'], ['v', 'y']],
    numeric: [['6', '9'], ['2', '5'], ['1', '7'], ['0', '8'], ['3', '8'], ['4', '7']],
    semantic: [['dere', 'dede'], ['baba', 'dada'], ['kasa', 'masa'], ['kale', 'lale'], ['kitap', 'katip'], ['sarı', 'darı'], ['para', 'yara'], ['kuzu', 'kutu'], ['etek', 'elek'], ['bal', 'dal']],
    pictographic: [['▲', '▼'], ['◀', '▶'], ['⬈', '⬉'], ['◐', '◑'], ['◒', '◓'], ['◖', '◗'], ['⊕', '⊗'], ['∿', '≈']]
};

export const generateOfflineFindTheDifference = async (options: GeneratorOptions): Promise<FindTheDifferenceData[]> => {
    const { worksheetCount, difficulty, findDiffType = 'linguistic', distractionLevel = 'medium', itemCount = 8, gridSize = 4 } = options;
    const results: FindTheDifferenceData[] = [];

    const getTitle = (type: string) => {
        switch(type) {
            case 'numeric': return 'Sayısal Ayrıştırma Analizi';
            case 'semantic': return 'Kelime Dedektifi';
            case 'pictographic': return 'Sembolik Görsel Dikkat';
            default: return 'Harf Ayrıştırma Analizi';
        }
    };

    for (let p = 0; p < worksheetCount; p++) {
        const rows = [];
        const pairPool = CRITICAL_PAIRS[findDiffType] || CRITICAL_PAIRS.linguistic;

        for (let i = 0; i < itemCount; i++) {
            const pair = pairPool[getRandomInt(0, pairPool.length - 1)];
            const baseChar = pair[0];
            const oddChar = pair[1];

            const correctIndex = getRandomInt(0, gridSize - 1);
            const items = Array.from({ length: gridSize }, (_, idx) => idx === correctIndex ? oddChar : baseChar);

            rows.push({
                items,
                correctIndex,
                visualDistractionLevel: distractionLevel as any
            });
        }

        results.push({
            title: getTitle(findDiffType),
            instruction: "Her satırı dikkatle inceleyin. Diğerlerinden farklı olan tek öğeyi bulun ve işaretleyin.",
            pedagogicalNote: `Bu çalışma ${findDiffType} mimarisi üzerinden görsel ayrıştırma ve sürdürülebilir dikkat becerilerini ${difficulty} düzeyinde güçlendirir.`,
            rows: shuffle(rows)
        });
    }
    return results;
};

