                    </div>

                    <CompactToggleGroup 
                        label="Çeldirici Şiddeti" 
                        selected={options.distractionLevel} 
                        onChange={(v: string) => handleChange('distractionLevel', v)} 
                        options={[
                            { value: 'low', label: 'DÜŞÜK' },
                            { value: 'medium', label: 'ORTA' },
